query:
UPDATE site_content SET value = 'Where Raga Meets Jazz' WHERE `key` = 'hero_subtitle' AND lang = 'en';
UPDATE site_content SET value = 'An exploration of the space between Indian classical music and jazz, where raga and improvisation meet in unexpected and beautiful ways.' WHERE `key` = 'hero_quote' AND lang = 'en';
UPDATE site_content SET value = 'Essence of Duality is the debut crossover jazz album by Cologne-based sitarist Hindol Deb. The album explores and crosses the boundaries of jazz and Indian classical music, making aesthetic connections between the two. It is a sincere attempt to move beyond the exotic yet stereotypical image of the sitar in the West, and of Indo-Jazz fusion in particular. The album is the logical result of Hindol''s move to Germany in 2015, in search of new sounds and compositional styles.' WHERE `key` = 'album_description' AND lang = 'en';
UPDATE site_content SET value = 'October 1, 2021' WHERE `key` = 'album_release' AND lang = 'en';
UPDATE site_content SET value = 'Medieval Raga Records' WHERE `key` = 'album_label' AND lang = 'en';
UPDATE site_content SET value = 'It started with the duality of two styles of music. On the one hand, my classical Indian background, which I brought with me to Germany, and on the other, music built on harmonies. I had wanted to bring these two worlds together ever since I listened to the late night shows on the radio in 10th grade.' WHERE `key` = 'artist_quote' AND lang = 'en';
UPDATE site_content SET value = 'Each composition on the album is rooted in a specific raga — the melodic framework of Indian classical music. Hindol Deb uses ragas outside their traditional time-of-day assignments, sometimes relating two or three ragas in a single composition, and combines them with European harmonic cadences to create entirely new timbres.' WHERE `key` = 'ragas_intro' AND lang = 'en';
UPDATE site_content SET value = 'Hindol Deb is an internationally renowned Indian classical sitarist whose artistry is defined by a profound adherence to his traditional heritage and a visionary quest for musical expansion. Representing the celebrated Maihar and Rampur Gharanas, Hindol has established himself as a virtuoso who bridges the ancient spiritual depth of the Raga with the infinite possibilities of global contemporary music.\n\nHindol''s journey began at age five under his father, Sri Panchanan Sardar. He underwent rigorous training with Pandit Santosh Banerjee (Rampur Gharana) and Pandit Deepak Chaudhury (Maihar Gharana), a disciple of Pandit Ravi Shankar. Deeply influenced by masters like Ali Akbar Khan, Nikhil Banerji, and Zia-Mohiuddin Dagar, Hindol developed a unique style integrating the meditative Dhrupad Ang and the vocal-like Been Ang onto the sitar.\n\nWhile maintaining his classical core, Hindol earned a Master''s in Jazz Instrumental Music from the Hochschule für Musik und Tanz Köln. His global footprint spans collaborations with icons such as Marina Abramovic, Renaud Garcia Fons, Markus Stockhausen and George Xylouris. He has performed Ravi Shankar''s Sitar Concerto No. 1 with the Bochum Symphony Orchestra, the Junge Symphoniker Hamburg, and the WDR Funkhausorchester.' WHERE `key` = 'artist_bio' AND lang = 'en';

